#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <chrono>
#include <cuda_runtime.h>

template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * (int64_t)sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (ref_out[i] != out[i]) {
        printf("@%zu: %lf != %lf\n", (size_t)i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

static inline void cuda_check(cudaError_t err)
{
  if (err != cudaSuccess) {
    fprintf(stderr, "CUDA error: %s\n", cudaGetErrorString(err));
    exit(1);
  }
}

template<typename T, int N>
__global__ void scan_with_bank_conflicts(const T* in, T* out, int64_t num_blocks)
{
  if ((int64_t)blockIdx.x >= num_blocks) return;
  const int thid = threadIdx.x;
  if (thid >= (N / 2)) return;

  extern __shared__ __align__(16) unsigned char smem_raw[];
  T* temp = reinterpret_cast<T*>(smem_raw);

  int64_t bid = (int64_t)blockIdx.x;
  const T* t_in = in + bid * N;
  T* t_out = out + bid * N;

  int offset = 1;

  temp[2 * thid]     = t_in[2 * thid];
  temp[2 * thid + 1] = t_in[2 * thid + 1];

  for (int d = N >> 1; d > 0; d >>= 1) {
    __syncthreads();
    if (thid < d) {
      int ai = offset * (2 * thid + 1) - 1;
      int bi = offset * (2 * thid + 2) - 1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N - 1] = 0;

  for (int d = 1; d < N; d *= 2) {
    offset >>= 1;
    __syncthreads();
    if (thid < d) {
      int ai = offset * (2 * thid + 1) - 1;
      int bi = offset * (2 * thid + 2) - 1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }

  t_out[2 * thid]     = temp[2 * thid];
  t_out[2 * thid + 1] = temp[2 * thid + 1];
}

template<typename T, int N>
__global__ void scan_without_bank_conflicts(const T* in, T* out, int64_t num_blocks)
{
  if ((int64_t)blockIdx.x >= num_blocks) return;
  const int thid = threadIdx.x;
  if (thid >= (N / 2)) return;

  extern __shared__ __align__(16) unsigned char smem_raw[];
  T* temp = reinterpret_cast<T*>(smem_raw);

  int64_t bid = (int64_t)blockIdx.x;
  const T* t_in = in + bid * N;
  T* t_out = out + bid * N;

  int a = thid;
  int b = a + (N / 2);
  int oa = OFFSET(a);
  int ob = OFFSET(b);

  temp[a + oa] = t_in[a];
  temp[b + ob] = t_in[b];

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1) {
    __syncthreads();
    if (thid < d) {
      int ai = offset * (2 * thid + 1) - 1;
      int bi = offset * (2 * thid + 2) - 1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N - 1 + OFFSET(N - 1)] = 0;

  for (int d = 1; d < N; d *= 2) {
    offset >>= 1;
    __syncthreads();
    if (thid < d) {
      int ai = offset * (2 * thid + 1) - 1;
      int bi = offset * (2 * thid + 2) - 1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }

  __syncthreads();

  t_out[a] = temp[a + oa];
  t_out[b] = temp[b + ob];
}

template<typename T, int N>
void runTest(const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N;
  int64_t bytes = nelems * (int64_t)sizeof(T);

  size_t host_alloc_bytes = bytes > 0 ? (size_t)bytes : (size_t)1;
  T* in = (T*)malloc(host_alloc_bytes);
  T* out = (T*)malloc(host_alloc_bytes);
  T* ref_out = (T*)malloc(host_alloc_bytes);

  srand(123);
  for (int64_t i = 0; i < nelems; i++) in[i] = (T)(rand() % 5 + 1);

  T* t_in = in;
  T* t_out = ref_out;
  for (int64_t blk = 0; blk < num_blocks; blk++) {
    t_out[0] = 0;
    for (int i = 1; i < N; i++)
      t_out[i] = t_out[i - 1] + t_in[i - 1];
    t_out += N;
    t_in += N;
  }

  T *d_in = nullptr, *d_out = nullptr;
  if (bytes > 0) {
    cuda_check(cudaMalloc((void**)&d_in, (size_t)bytes));
    cuda_check(cudaMalloc((void**)&d_out, (size_t)bytes));
    cuda_check(cudaMemcpy(d_in, in, (size_t)bytes, cudaMemcpyHostToDevice));
  }

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    if (num_blocks > 0) {
      scan_with_bank_conflicts<T, N><<<(unsigned int)num_blocks, N / 2, N * sizeof(T)>>>(d_in, d_out, num_blocks);
      cuda_check(cudaGetLastError());
      cuda_check(cudaDeviceSynchronize());
    }
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }

  if (bytes > 0) {
    cuda_check(cudaMemcpy(out, d_out, (size_t)bytes, cudaMemcpyDeviceToHost));
  }
  if (!timing) verify(ref_out, out, nelems);

  start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    if (num_blocks > 0) {
      scan_without_bank_conflicts<T, N><<<(unsigned int)num_blocks, N / 2, (2 * N) * sizeof(T)>>>(d_in, d_out, num_blocks);
      cuda_check(cudaGetLastError());
      cuda_check(cudaDeviceSynchronize());
    }
  }

  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  if (bytes > 0) {
    cuda_check(cudaMemcpy(out, d_out, (size_t)bytes, cudaMemcpyDeviceToHost));
  }
  if (!timing) verify(ref_out, out, nelems);

  if (d_in) cuda_check(cudaFree(d_in));
  if (d_out) cuda_check(cudaFree(d_out));
  free(in);
  free(out);
  free(ref_out);
}

template<int N>
void run(const int n, const int repeat)
{
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int n = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  run< 128>(n, repeat);
  run< 256>(n, repeat);
  run< 512>(n, repeat);
  run<1024>(n, repeat);
  run<2048>(n, repeat);

  return 0;
}
